import { useAuth, useSession } from "@better-auth-ui/solid"
import type { User as AuthUserBase } from "better-auth"
import { Show } from "solid-js"
import { Skeleton } from "@/components/ui/skeleton"
import { cn } from "@/lib/utils"
import { UserAvatar } from "./user-avatar"

type AuthUser = AuthUserBase & {
  displayUsername?: string | null
  username?: string | null
}

export type UserViewProps = {
  class?: string
  image?: string | null
  initials?: string
  isPending?: boolean
  label?: string
  secondaryLabel?: string | null
  user?: AuthUser
}

const resolvePrimaryLabel = (user?: AuthUser, label?: string) =>
  label ??
  user?.displayUsername ??
  user?.username ??
  user?.name ??
  user?.email ??
  "Account"

const resolveSecondaryLabel = (
  user?: AuthUser,
  secondaryLabel?: string | null
) =>
  secondaryLabel ??
  (user?.displayUsername || user?.username || user?.name
    ? user?.email
    : undefined)

export function UserView(props: UserViewProps) {
  const auth = useAuth()
  const session = useSession(auth.authClient, {
    enabled: !props.user && !props.isPending && !props.label
  })
  const sessionPending = () => session.isPending
  const resolvedUser = () =>
    props.user ?? (session.data?.user as AuthUser | undefined)
  const label = () => resolvePrimaryLabel(resolvedUser(), props.label)
  const secondaryLabel = () =>
    resolveSecondaryLabel(resolvedUser(), props.secondaryLabel)

  if ((props.isPending || sessionPending()) && !props.user && !props.label) {
    return (
      <div class={cn("flex items-center gap-2", props.class)}>
        <UserAvatar isPending />
        <div class="grid flex-1 gap-1 text-left text-sm">
          <Skeleton class="h-4 w-24" />
          <Skeleton class="h-3 w-32" />
        </div>
      </div>
    )
  }

  return (
    <div class={cn("contents", props.class)}>
      <UserAvatar
        user={resolvedUser()}
        image={props.image}
        initials={props.initials}
        label={label()}
      />

      <div class="grid min-w-0 flex-1 gap-0.5 text-sm">
        <span class="truncate font-medium leading-4 text-foreground">
          {label()}
        </span>

        <Show when={secondaryLabel()}>
          <span class="truncate text-xs leading-4 text-muted-foreground">
            {secondaryLabel()}
          </span>
        </Show>
      </div>
    </div>
  )
}

import { useAuth, useSession } from "@better-auth-ui/solid"
import type { User as AuthUserBase } from "better-auth"
import { User } from "lucide-solid"
import type { JSX } from "solid-js"
import { Show } from "solid-js"
import { Avatar, AvatarFallback, AvatarImage } from "@/components/ui/avatar"
import { Skeleton } from "@/components/ui/skeleton"
import { cn } from "@/lib/utils"

type AuthUser = AuthUserBase & {
  displayUsername?: string | null
  username?: string | null
}

export type UserAvatarProps = {
  class?: string
  fallback?: JSX.Element
  image?: string | null
  initials?: string
  isPending?: boolean
  label?: string
  user?: AuthUser
}

const resolveAvatarLabel = (user?: AuthUser, label?: string) =>
  label ??
  user?.displayUsername ??
  user?.username ??
  user?.name ??
  user?.email ??
  "Account"

const resolveAvatarInitials = (
  user?: AuthUser,
  initials?: string,
  label?: string
) => initials ?? resolveAvatarLabel(user, label).slice(0, 2).toUpperCase()

export function UserAvatar(props: UserAvatarProps) {
  const auth = useAuth()
  const session = useSession(auth.authClient, {
    enabled: !props.user && !props.isPending
  })
  const sessionPending = () => session.isPending
  const resolvedUser = () =>
    props.user ?? (session.data?.user as AuthUser | undefined)
  const label = () => resolveAvatarLabel(resolvedUser(), props.label)
  const initials = () =>
    resolveAvatarInitials(resolvedUser(), props.initials, props.label)

  if ((props.isPending || sessionPending()) && !props.user) {
    return (
      <Skeleton
        class={cn(
          "size-9 rounded-full bg-muted text-muted-foreground",
          props.class
        )}
      />
    )
  }

  return (
    <Avatar
      class={cn(
        "size-9 rounded-full bg-muted text-muted-foreground",
        props.class
      )}
    >
      <AvatarImage
        alt={label()}
        src={props.image ?? resolvedUser()?.image ?? undefined}
      />
      <AvatarFallback class="rounded-full bg-muted text-muted-foreground">
        <Show
          fallback={props.fallback ?? <User class="size-4" />}
          when={initials()}
        >
          {(initials) => initials()}
        </Show>
      </AvatarFallback>
    </Avatar>
  )
}

import * as ImagePrimitive from "@kobalte/core/image"
import type { PolymorphicProps } from "@kobalte/core/polymorphic"
import type { ComponentProps, ValidComponent } from "solid-js"
import { mergeProps, splitProps } from "solid-js"

import { cn } from "@/lib/utils"

type AvatarRootProps<T extends ValidComponent = "span"> = PolymorphicProps<
  T,
  ImagePrimitive.ImageRootProps<T>
> &
  Pick<ComponentProps<T>, "class"> & {
    size?: "sm" | "default" | "lg"
  }

const Avatar = <T extends ValidComponent = "span">(
  props: AvatarRootProps<T>
) => {
  const mergedProps = mergeProps({ size: "default" }, props)
  const [local, others] = splitProps(mergedProps as AvatarRootProps, [
    "class",
    "size"
  ])

  return (
    <ImagePrimitive.Root
      class={cn(
        "group/avatar relative z-avatar flex shrink-0 select-none after:absolute after:inset-0 after:border after:border-border after:mix-blend-darken dark:after:mix-blend-lighten",
        local.class
      )}
      data-size={local.size}
      data-slot="avatar"
      {...others}
    />
  )
}

type AvatarImageProps<T extends ValidComponent = "img"> = PolymorphicProps<
  T,
  ImagePrimitive.ImageImgProps<T>
> &
  Pick<ComponentProps<T>, "class">

const AvatarImage = <T extends ValidComponent = "img">(
  props: AvatarImageProps<T>
) => {
  const [local, others] = splitProps(props as AvatarImageProps, ["class"])

  return (
    <ImagePrimitive.Img
      class={cn(
        "z-avatar-image aspect-square size-full object-cover",
        local.class
      )}
      data-slot="avatar-image"
      {...others}
    />
  )
}

type AvatarFallbackProps<T extends ValidComponent = "span"> = PolymorphicProps<
  T,
  ImagePrimitive.ImageFallbackProps<T>
> &
  Pick<ComponentProps<T>, "class">

const AvatarFallback = <T extends ValidComponent = "span">(
  props: AvatarFallbackProps<T>
) => {
  const [local, others] = splitProps(props as AvatarFallbackProps, ["class"])

  return (
    <ImagePrimitive.Fallback
      class={cn(
        "z-avatar-fallback flex size-full items-center justify-center text-sm group-data-[size=sm]/avatar:text-xs",
        local.class
      )}
      data-slot="avatar-fallback"
      {...others}
    />
  )
}

type AvatarBadgeProps = ComponentProps<"span">

function AvatarBadge(props: AvatarBadgeProps) {
  const [local, others] = splitProps(props as AvatarBadgeProps, ["class"])

  return (
    <span
      data-slot="avatar-badge"
      class={cn(
        "absolute right-0 bottom-0 z-10 z-avatar-badge inline-flex select-none items-center justify-center rounded-full bg-blend-color ring-2",
        "group-data-[size=sm]/avatar:size-2 group-data-[size=sm]/avatar:[&>svg]:hidden",
        "group-data-[size=default]/avatar:size-2.5 group-data-[size=default]/avatar:[&>svg]:size-2",
        "group-data-[size=lg]/avatar:size-3 group-data-[size=lg]/avatar:[&>svg]:size-2",
        local.class
      )}
      {...others}
    />
  )
}

type AvatarGroupProps = ComponentProps<"div">

function AvatarGroup(props: AvatarGroupProps) {
  const [local, others] = splitProps(props as AvatarGroupProps, ["class"])

  return (
    <div
      data-slot="avatar-group"
      class={cn(
        "group/avatar-group z-avatar-group flex -space-x-2 *:data-[slot=avatar]:ring-2 *:data-[slot=avatar]:ring-background",
        local.class
      )}
      {...others}
    />
  )
}

type AvatarGroupCountProps = ComponentProps<"div">

function AvatarGroupCount(props: AvatarGroupCountProps) {
  const [local, others] = splitProps(props as AvatarGroupCountProps, ["class"])

  return (
    <div
      data-slot="avatar-group-count"
      class={cn(
        "relative z-avatar-group-count flex shrink-0 items-center justify-center ring-2 ring-background",
        local.class
      )}
      {...others}
    />
  )
}

export {
  Avatar,
  AvatarBadge,
  AvatarFallback,
  AvatarGroup,
  AvatarGroupCount,
  AvatarImage
}

import { type ClassValue, clsx } from "clsx"
import { twMerge } from "tailwind-merge"

export const cn = (...inputs: ClassValue[]) => twMerge(clsx(inputs))
